  1→import { MouseEvent, useEffect, useMemo, useRef, useState } from "react";
  2→import type {
  3→  Session,
  4→  Suggestion,
  5→  MentionItem,
  6→  ChatInputRef,
  7→} from "reachat";
  8→import type {
  9→  BranchConversationResponse,
 10→  ChatMessageResponse,
 11→  OnboardingAction,
 12→  SearchEntityResponse,
 13→  StreamEvent as ChatStreamEvent,
 14→  WorkspaceConversationResponse,
 15→} from "../../shared/contracts";
 16→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 17→import { useViewState } from "../stores/view-state";
 18→
 19→type UseChatSessionReturn = {
 20→  sessions: Session[];
 21→  activeSessionId: string;
 22→  activeSession: Session;
 23→  activeConversationId?: string;
 24→  isLoading: boolean;
 25→  errorMessage?: string;
 26→  suggestions: Suggestion[];
 27→  pendingFile?: File;
 28→  branchingFromId?: string;
 29→  inheritedMessageIds: Set<string>;
 30→  chatInputRef: React.RefObject<ChatInputRef | null>;
 31→  onSendMessage: (message: string, options?: { onboardingAction?: OnboardingAction }) => Promise<void>;
 32→  onStopMessage: () => void;
 33→  onNewConversation: () => void;
 34→  onSelectConversation: (conversationId: string) => void;
 35→  onBranchFromMessage: (messageId: string) => Promise<void>;
 36→  searchMentions: (query: string) => Promise<MentionItem[]>;
 37→  onUploadFile: (file: File) => void;
 38→  onChatInputClickCapture: (event: MouseEvent<HTMLDivElement>) => void;
 39→  setErrorMessage: (message: string | undefined) => void;
 40→  refreshSidebar: (workspaceId: string) => Promise<void>;
 41→};
 42→
 43→export function useChatSession(): UseChatSessionReturn {
 44→  const store = useWorkspaceState();
 45→  const workspaceId = store.workspaceId;
 46→  const workspaceName = store.workspaceName;
 47→  const bootstrapPayload = store.bootstrapPayload;
 48→
 49→  const [sessions, setSessions] = useState<Session[]>([
 50→    {
 51→      id: "main",
 52→      title: "Workspace Chat",
 53→      createdAt: new Date(),
 54→      updatedAt: new Date(),
 55→      conversations: [],
 56→    },
 57→  ]);
 58→  const [activeSessionId] = useState("main");
 59→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 60→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 61→  const [isLoading, setIsLoading] = useState(false);
 62→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 63→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 64→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 65→  const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
 66→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 67→  const streamRef = useRef<EventSource | undefined>(undefined);
 68→  const chatInputRef = useRef<ChatInputRef | null>(null);
 69→
 70→  // Track the last applied bootstrap payload to avoid re-applying
 71→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
 72→
 73→  const activeSession = useMemo(
 74→    () => sessions.find((session) => session.id === activeSessionId),
 75→    [sessions, activeSessionId],
 76→  );
 77→
 78→  if (!activeSession) {
 79→    throw new Error("active session missing");
 80→  }
 81→
 82→  // Apply bootstrap payload when it arrives
 83→  useEffect(() => {
 84→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
 85→      return;
 86→    }
 87→    appliedBootstrapRef.current = bootstrapPayload;
 88→
 89→    setSessions([
 90→      {
 91→        id: "main",
 92→        title: workspaceName ?? "Workspace Chat",
 93→        createdAt: new Date(),
 94→        updatedAt: new Date(),
 95→        conversations: bootstrapPayload.conversations,
 96→      },
 97→    ]);
 98→    setInheritedMessageIds(bootstrapPayload.inheritedIds);
 99→    setSuggestions(
100→      bootstrapPayload.latestSuggestions.map((content, index) => ({
101→        id: `bootstrap-suggestion-${index}-${content}`,
102→        content,
103→      })),
104→    );
105→    setActiveConversationId(store.conversationId);
106→    setBackendConversationId(store.conversationId);
107→  }, [bootstrapPayload]);
108→
109→  // Highlight message support (graph -> chat navigation)
110→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
111→  const clearHighlight = useViewState((s) => s.clearHighlight);
112→
113→  useEffect(() => {
114→    if (!highlightMessageId) return;
115→
116→    const timer = setTimeout(() => {
117→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
118→      if (element) {
119→        element.scrollIntoView({ behavior: "smooth", block: "center" });
120→        element.classList.add("animate-highlight");
121→        element.addEventListener(
122→          "animationend",
123→          () => {
124→            element.classList.remove("animate-highlight");
125→          },
126→          { once: true },
127→        );
128→      }
129→      clearHighlight();
130→    }, 100);
131→
132→    return () => clearTimeout(timer);
133→  }, [highlightMessageId, clearHighlight]);
134→
135→  async function refreshSidebar(wsId: string) {
136→    try {
137→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
138→      if (response.ok) {
139→        const payload = await response.json();
140→        store.setSidebar(payload);
141→      }
142→    } catch {
143→      // Sidebar refresh is non-critical; silently ignore
144→    }
145→  }
146→
147→  async function loadConversation(wsId: string, conversationId: string) {
148→    try {
149→      const response = await fetch(
150→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
151→      );
152→      if (!response.ok) {
153→        const body = await response.text();
154→        setErrorMessage(body);
155→        return;
156→      }
157→
158→      const payload = (await response.json()) as WorkspaceConversationResponse;
159→      const conversations: Session["conversations"] = [];
160→      let latestSuggestions: string[] = [];
161→      const inheritedIds = new Set<string>();
162→
163→      for (const message of payload.messages) {
164→        if (message.role === "user") {
165→          conversations.push({
166→            id: message.id,
167→            question: message.text,
168→            createdAt: new Date(message.createdAt),
169→          });
170→          if (message.inherited) {
171→            inheritedIds.add(message.id);
172→          }
173→          continue;
174→        }
175→
176→        const last = conversations[conversations.length - 1];
177→        if (last && !last.response) {
178→          last.response = message.text;
179→          last.updatedAt = new Date(message.createdAt);
180→          latestSuggestions =
181→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
182→          if (message.inherited) {
183→            inheritedIds.add(last.id);
184→          }
185→          continue;
186→        }
187→
188→        conversations.push({
189→          id: `assistant-${message.id}`,
190→          question: "System kickoff",
191→          response: message.text,
192→          createdAt: new Date(message.createdAt),
193→        });
194→        if (message.inherited) {
195→          inheritedIds.add(`assistant-${message.id}`);
196→        }
197→        latestSuggestions =
198→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
199→      }
200→
201→      setInheritedMessageIds(inheritedIds);
202→      setSessions([
203→        {
204→          id: "main",
205→          title: workspaceName ?? "Workspace Chat",
206→          createdAt: new Date(),
207→          updatedAt: new Date(),
208→          conversations,
209→        },
210→      ]);
211→
212→      setSuggestions(
213→        latestSuggestions.map((content, index) => ({
214→          id: `conv-suggestion-${index}-${content}`,
215→          content,
216→        })),
217→      );
218→
219→      setActiveConversationId(conversationId);
220→      setBackendConversationId(conversationId);
221→    } catch (error) {
222→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
223→      setErrorMessage(messageText);
224→    }
225→  }
226→
227→  function onNewConversation() {
228→    setActiveConversationId(undefined);
229→    setBackendConversationId(undefined);
230→    setSessions([
231→      {
232→        id: "main",
233→        title: workspaceName ?? "Workspace Chat",
234→        createdAt: new Date(),
235→        updatedAt: new Date(),
236→        conversations: [],
237→      },
238→    ]);
239→    setSuggestions([]);
240→    setErrorMessage(undefined);
241→  }
242→
243→  function onSelectConversation(conversationId: string) {
244→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
245→      return;
246→    }
247→
248→    void loadConversation(workspaceId, conversationId);
249→  }
250→
251→  async function onBranchFromMessage(messageId: string) {
252→    if (!workspaceId || !activeConversationId || isLoading) return;
253→
254→    setBranchingFromId(messageId);
255→    try {
256→      const response = await fetch(
257→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
258→        {
259→          method: "POST",
260→          headers: { "Content-Type": "application/json" },
261→          body: JSON.stringify({ messageId }),
262→        },
263→      );
264→
265→      if (!response.ok) {
266→        const body = await response.text();
267→        setErrorMessage(body);
